using System;
using System.Diagnostics;
using System.IO;
using System.Windows.Forms;
class Setup {
    [STAThread]
    static void Main() {
        string appData = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
        string installDir = Path.Combine(appData,"OpenXterm");
        string srcDir = Path.Combine(installDir,"src");
        Directory.CreateDirectory(srcDir);
        File.WriteAllText(Path.Combine(srcDir,"__init__.py"),"");
        File.WriteAllBytes(Path.Combine(srcDir,"main.py"),
            Convert.FromBase64String(@""));
        File.WriteAllBytes(Path.Combine(srcDir,"crypto.py"),
            Convert.FromBase64String(@""));
        File.WriteAllBytes(Path.Combine(srcDir,"db.py"),
            Convert.FromBase64String(@""));
        File.WriteAllBytes(Path.Combine(srcDir,"parser.py"),
            Convert.FromBase64String(@""));
        string launcherPath = Path.Combine(installDir,"OpenXterm.exe");
        try{
            if(!File.Exists(launcherPath))
                File.Copy(Application.ExecutablePath,launcherPath);
        }catch{}
        string python = FindPython();
        if(python==null){
            MessageBox.Show("需要 Python 3.10+","OpenXterm",MessageBoxButtons.OK,MessageBoxIcon.Error);
            return;
        }
        try{
            CreateShortcut("OpenXterm",launcherPath,installDir);
        }catch{}
        try{
            string mainPy=Path.Combine(srcDir,"main.py");
            var psi=new ProcessStartInfo(python,"\""+mainPy+"\""){WorkingDirectory=installDir,UseShellExecute=false};
            psi.EnvironmentVariables["PYTHONIOENCODING"]="utf-8";
            Process.Start(psi);
        }catch(Exception ex){
            MessageBox.Show("错误: "+ex.Message,"OpenXterm",MessageBoxButtons.OK,MessageBoxIcon.Error);
        }
    }
    static void CreateShortcut(string name,string target,string wdir){
        string menu=Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.StartMenu),
            "Programs");
        string lnk=Path.Combine(menu,name+".lnk");
        try{
            var t=Type.GetTypeFromProgID("WScript.Shell");
            dynamic s=Activator.CreateInstance(t);
            dynamic sc=s.CreateShortcut(lnk);
            sc.TargetPath=target;
            sc.WorkingDirectory=wdir;
            sc.Save();
        }catch{}
    }
    static string FindPython(){
        string p=Environment.GetEnvironmentVariable("PATH");
        if(p!=null){
            foreach(string d in p.Split(';')){
                string dir=d.Trim();if(dir.Length==0)continue;
                try{string pp=Path.Combine(dir,"python.exe");if(File.Exists(pp))return pp;}catch{}
            }
        }
        return null;
    }
}